import React from 'react';
import { Link } from 'react-router-dom';

function Navbar({ user, onLogout }) {
  const linkStyle = {
    fontSize: '12px',
    fontWeight: '300',
    fontFamily: 'Helvetica, Arial, sans-serif',
    color: '#000',
    textDecoration: 'none',
    letterSpacing: '0.5px'
  };

  return (
    <nav style={{
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      padding: '15px 30px',
      backgroundColor: '#fff',
      borderBottom: '1px solid #f0f0f0',
      gap: '40px',
      fontFamily: 'Helvetica, Arial, sans-serif'
    }}>
      {/* Left Menu */}
      <div style={{ display: 'flex', gap: '30px' }}>
        <Link to="/products" style={linkStyle}>WOMEN</Link>
        <Link to="/products" style={linkStyle}>MEN</Link>
        <Link to="/products" style={linkStyle}>HANDBAGS</Link>
        <Link to="/products" style={linkStyle}>HOME</Link>
        <Link to="/products" style={linkStyle}>COLLECTIONS</Link>
      </div>

      {/* Center - Logo */}
      <Link to="/" style={{ display: 'flex', alignItems: 'center', margin: '0 40px' }}>
        <img src="/TheRawLogo.svg" alt="Clothing Shop" style={{ height: '35px', width: 'auto' }} />
      </Link>

      {/* Right Menu */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '30px' }}>
        <Link to="/" style={linkStyle}>SEARCH</Link>
        <Link to="/" style={linkStyle}>STORES</Link>
        <Link to="/" style={linkStyle}>SAVED</Link>
        {user ? (
          <>
            <Link to="/profile" style={linkStyle}>ACCOUNT</Link>
            <Link to="/orders" style={linkStyle}>ORDERS</Link>
            <button onClick={onLogout} style={{ ...linkStyle, background: 'none', border: 'none', cursor: 'pointer', padding: '0' }}>LOGOUT</button>
          </>
        ) : (
          <>
            <Link to="/login" style={linkStyle}>LOGIN</Link>
            <Link to="/cart" style={linkStyle}>BAG</Link>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
